// Cycle through the pin list, one per run, no state file needed.
const data = $input.first().json;
const pins = (data && data.pins) || [];
if (!pins.length) { throw new Error('pins.json empty'); }
const store = $getWorkflowStaticData('global');
let idx = typeof store.idx === 'number' ? store.idx : 0;
if (idx >= pins.length) idx = 0;
const pin = pins[idx];
store.idx = idx + 1;
// Pinterest description = title + description (kept under ~490 chars)
const text = (pin.title + '\n\n' + pin.description).slice(0, 490);
return [{ json: { text, image: pin.image, link: pin.link, board: pin.board, slug: pin.slug } }];
